mapper.select:
SELECT er.id AS id, er.student_name AS studentName, er.score AS score, er.exam_id AS examId, p.name AS paperName, p.total_score AS paperTotalScore, er.start_time AS startTime, er.end_time AS endTime, TIMESTAMPDIFF(MINUTE, er.start_time, er.end_time) AS duration FROM exam_records er LEFT JOIN paper p ON er.exam_id = p.id WHERE er.status = '已批阅' AND er.is_deleted = 0 AND p.is_deleted = 0
AND er.exam_id = #{paperId}
ORDER BY er.score DESC
LIMIT #{limit}
